#include <stdio.h>

/*
 * Square-and-Multiply Algorithm for Modular Exponentiation
 * Computes: result = base^exponent mod modulus
 * 
 * This is the core operation in RSA encryption/decryption:
 * Encryption: C = M^e mod n
 * Decryption: M = C^d mod n
 */
unsigned long long square_and_multiply(unsigned long long base, 
                                        unsigned long long exponent, 
                                        unsigned long long modulus) {
    unsigned long long result = 1;
    base = base % modulus;

    while (exponent > 0) {
        // If LSB is 1, multiply result by base
        if (exponent & 1) {
            result = (result * base) % modulus;
        }
        // Square the base
        base = (base * base) % modulus;
        // Right shift exponent
        exponent >>= 1;
    }

    return result;
}

// Alternative: Left-to-right binary exponentiation (pre-computes powers)
square_and_multiply_lr(unsigned long long base,
                        unsigned long long exponent,
                        unsigned long long modulus) {
    unsigned long long result = 1;
    unsigned long long power = base % modulus;

    // Process bits from MSB to LSB
    while (exponent > 0) {
        if (exponent & 1) {
            result = (result * power) % modulus;
        }
        power = (power * power) % modulus;
        exponent >>= 1;
    }

    return result;
}

int main() {
    // Example: RSA-like encryption
    unsigned long long M = 65;    // Message
    unsigned long long e = 17;    // Public exponent
    unsigned long long n = 3233;  // Modulus (61 * 53)

    // Encryption: C = M^e mod n
    unsigned long long ciphertext = square_and_multiply(M, e, n);

    printf("=== RSA-like Encryption Demo ===\n");
    printf("Message M:   %llu\n", M);
    printf("Exponent e:  %llu\n", e);
    printf("Modulus n:   %llu\n", n);
    printf("Ciphertext:  %llu\n", ciphertext);

    // Decryption: M = C^d mod n
    unsigned long long d = 2753;  // Private exponent
    unsigned long long decrypted = square_and_multiply(ciphertext, d, n);

    printf("\n=== RSA-like Decryption Demo ===\n");
    printf("Private key d: %llu\n", d);
    printf("Decrypted:     %llu\n", decrypted);

    // Demonstrate efficiency: compare with naive approach
    printf("\n=== Complexity Comparison ===\n");
    printf("For exponent e=17:\n");
    printf("  Naive:     17 multiplications\n");
    printf("  Our method: %d multiplications (log2(17) ≈ 4.09)\n", 5);

    return 0;
}
